import{_ as e,o as a,c as r,a7 as p}from"./chunks/framework.BgApuQ2e.js";const n="/images/but-what-about-greenland/Greenland1-682x1024.png",o="/images/but-what-about-greenland/Sad-Greenland-FEATURE-FB-2-971x1024.png",l="/images/but-what-about-greenland/Tropics-1024x569.png",i="/images/but-what-about-greenland/Screen-Shot-2014-09-19-at-7.15.20-AM-1024x791.png",s="/images/but-what-about-greenland/world-map3-1024x627.jpg",h="/images/but-what-about-greenland/500px-Greenland_orthographic_projection.svg_.png",g="/images/but-what-about-greenland/IMG_53521-1024x547.jpg",m="/images/but-what-about-greenland/IMG_2738-1024x768.jpg",u="/images/but-what-about-greenland/IMG_5685-1024x330.jpg",c="/images/but-what-about-greenland/4874_1dd7.jpeg",b="/images/but-what-about-greenland/IMG_5633-1024x768.jpg",w="/images/but-what-about-greenland/iceberg-674x1024.jpg",_="/images/but-what-about-greenland/IMG_5651-1024x768.jpg",d="/images/but-what-about-greenland/Titanic_iceberg.jpg",f="/images/but-what-about-greenland/IMG_5606-1024x686.jpg",k="/images/but-what-about-greenland/IMG_5433-1024x768.jpg",y="/images/but-what-about-greenland/1325218.jpg",G="/images/but-what-about-greenland/IMG_5604-768x1024.jpg",j="/images/but-what-about-greenland/IMG_5597-1024x893.jpg",I="/images/but-what-about-greenland/IMG_5407-1024x520.jpg",M="/images/but-what-about-greenland/IMG_5523-1024x768.jpg",x="/images/but-what-about-greenland/IMG_5522-1024x768.jpg",q="/images/but-what-about-greenland/IMG_5529-768x1024.jpg",B="/images/but-what-about-greenland/IMG_5537-1024x768.jpg",S="/images/but-what-about-greenland/Scary-Compilation-1024x471.jpg",T="/images/but-what-about-greenland/pinit_fg_en_rect_gray_20.png",R=JSON.parse('{"title":"But What About Greenland?","description":"","frontmatter":{"title":"But What About Greenland?","titleZh":"那格陵兰呢","date":"2014-09-19T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/09/but-what-about-greenland.html","slug":"but-what-about-greenland"},"headers":[],"relativePath":"posts/but-what-about-greenland.md","filePath":"posts/but-what-about-greenland.md","lastUpdated":1782886257000}'),A={name:"posts/but-what-about-greenland.md"};function E(W,t,P,C,v,F){return a(),r("div",null,[...t[0]||(t[0]=[p('<h1 id="那格陵兰呢-·-but-what-about-greenland" tabindex="-1">那格陵兰呢 · But What About Greenland? <a class="header-anchor" href="#那格陵兰呢-·-but-what-about-greenland" aria-label="Permalink to &quot;那格陵兰呢 · But What About Greenland?&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/09/but-what-about-greenland.html</a> · 2014-09-19</p></blockquote><h2 id="如果你还不知道《奇怪之地的奇怪事物》-odd-things-in-odd-places-是什么、我为什么会跑到格陵兰-点这里看原委。" tabindex="-1">如果你还不知道《奇怪之地的奇怪事物》(Odd Things in Odd Places) 是什么、我为什么会跑到格陵兰,<a href="https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html" target="_blank" rel="noreferrer">点这里看原委</a>。 <a class="header-anchor" href="#如果你还不知道《奇怪之地的奇怪事物》-odd-things-in-odd-places-是什么、我为什么会跑到格陵兰-点这里看原委。" aria-label="Permalink to &quot;如果你还不知道《奇怪之地的奇怪事物》(Odd Things in Odd Places) 是什么、我为什么会跑到格陵兰,[点这里看原委](https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html)。&quot;">​</a></h2><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Greenland1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Greenland"></a></p><p>在《奇怪之地的奇怪事物》问卷的最后一题里,Wait But Why 的读者可以选择把我送去挪威、冰岛或者格陵兰。</p><p>挪威表现得不太好,这也不奇怪——虽然它是个宜人可爱的国家,但读者们并不觉得把我送去那儿会特别搞笑。而当最终结果出来时,冰岛和格陵兰的差距小到要看照片才能分胜负,格陵兰以一点点微弱优势险胜冰岛,这告诉我:相当一部分读者要么不太清楚冰岛是什么,要么不太清楚格陵兰是什么。</p><p>那我们现在把这事说清楚:冰岛是一个安静的、有点北欧风格的小型欧洲国家,只是名字取得莫名其妙地凶猛;格陵兰则是北极圈里一块巨大的冰坨,在那儿你就算尖叫也没人听得见。</p><p>话虽如此,这个结果让我兴奋极了。理所当然地,我卧室有一整面墙被一张巨型世界地图占据——而我人生中最能提神醒脑的活动之一,就是抬头盯着那块又大又白的格陵兰,心想:「那儿到底他妈的在发生什么?」</p><p>这种念头往往紧跟着一场 40 分钟的谷歌搜格陵兰之旅,所以我出发前对这个国家已经知道几件事了:<a href="#footnote-1-2432">1</a> ←点这里</p><ul><li>仅仅 2 亿年前,整个世界都是格陵兰的天下。那是盘古大陆 (Pangaea) 时期,所有大陆挤在一起相亲相爱,格陵兰<a href="http://cf.broadsheet.ie/wp-content/uploads/2013/05/pangea3.jpg" target="_blank" rel="noreferrer">就在正中间</a>。但后来大家玩腻了,<a href="https://www.youtube.com/watch?v=WaUk94AdXPA" target="_blank" rel="noreferrer">一哄而散</a>各奔东西,格陵兰一懵,结果孤零零地被甩到北极圈上头,连网速都很烂,从此就在那儿一直待着。</li></ul><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Sad-Greenland-FEATURE-FB-2.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="Sad Greenland"></a></p><ul><li><p>毫不意外,格陵兰是个冻死人的地方,夏天平均气温在华氏 30 到 40 多度(0 – 10 摄氏度)之间,冬天则常年零下(-15 到 -20 摄氏度)。</p></li><li><p>比气温更极端的,是格陵兰的日照情况。因为纬度太高,这个国家大部分地区整个冬天都是黑的,连白天也是黑的;整个夏天都是亮的,连晚上也是亮的。在国家的最北端,一年有 120 天太阳永不落下,108 天太阳永不升起,只有 137 天里既有白天又有黑夜。</p></li><li><p>既然说到这里,快速聊一下五条主要的纬线:</p><ul><li><strong>北极圈 (Arctic Circle)</strong> 是北半球最低的一条纬度线,越过这条线,每年至少会有一个冬日太阳不升起,以及至少一个夏日太阳不落下。你越往北越过北极圈,这样的日子每年就越多。<strong>南极圈 (Antarctic Circle)</strong> 就是南半球对应的情况。</li><li><strong>北回归线 (Tropic of Cancer)</strong> 是一年中某个时刻太阳会直射头顶的最高纬度线——对北回归线来说,那个时刻就是 6 月 21 日前后的夏至。<strong>南回归线 (Tropic of Capricorn)</strong> 是南半球的对应线,太阳在 12 月 21 日前后直射头顶。</li><li><strong>赤道 (The Equator)</strong> 是啥你们都知道。太阳会在 3 月和 9 月的春分和秋分时直射赤道。</li></ul></li></ul><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Tropics.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Tropics"></a></p><p>格陵兰大部分地区都在北极圈以北,所以那里的昼夜情况才这么极端。</p><ul><li><p>格陵兰是世界上最大的岛(大陆不算岛——不然的话啥都成岛了),不过有些考古学家认为格陵兰的冰把陆地压得太厉害了,如果把冰移走,格陵兰其实会变成一堆小岛,而不是一整块大岛。</p></li><li><p>格陵兰之所以叫格陵兰(意为「绿地」),是因为公元 982 年著名维京人红胡子埃里克 (Erik the Red) 在那里建立第一个欧洲殖民地时,决定这么叫它。他选了「格陵兰」这个名字,是为了让欧洲那边的人觉得听起来暖洋洋的,因为要成功开拓殖民地,他需要一大批愿意迁过去的定居者。所以这个名字其实是 10 世纪一场骗局留下的遗产。<a href="#footnote-2-2432">2</a></p></li><li><p>考虑到格陵兰在盘古大陆解体后的窘境,世界决定给格陵兰一点面子,在地图上假装它跟非洲一样大。</p></li></ul><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Screen-Shot-2014-09-19-at-7.15.20-AM.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Huge Greenland"></a></p><p><em>Google 地图</em></p><p>如果有人跟外星人讲了一个叫「地球」的遥远星球,然后给他看上面这张地图,在他眼里地球就好像分成了海洋、陆地、以及我们的至高统治者格陵兰。</p><p>有些地图没这么离谱,但即便如此,格陵兰还是被画得太大了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/world-map3.jpg" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Medium Greenland"></a></p><p><a href="https://commons.wikimedia.org/wiki/File:Winkel_triple_projection_SW.jpg" target="_blank" rel="noreferrer"><em>Strebe</em></a></p><p>造成这种现象的原因有两点:1) 很多地图(比如上面那张)都是以北为中心的,把赤道放在中心以下,于是纵向拉伸了北半球,同时纵向压扁了南半球;2) 为了把一个球面变成扁平的长方形,你得让每一条纬线都变成同样长——尽管在地球仪上纬线越靠近两极就越短——这就把最高和最低纬度横向拉长了(上面第二张地图用了椭圆形状,准确度更高,但两极仍然被横向拉伸)。格陵兰同时受这两种扭曲影响最严重,所以看起来巨大无比;而一张准确的、以北极为中心的地球仪图像会显示它的实际大小要小得多,差不多和沙特阿拉伯或苏丹一样大:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/500px-Greenland_orthographic_projection.svg_.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Arctic Centered Greenland"></a></p><p><a href="https://commons.wikimedia.org/wiki/User:Connormah" target="_blank" rel="noreferrer"><em>Connormah</em></a></p><p>几周前,我终于决定不再仰望这个庞大、神秘、却没人谈起的北极岛屿,而是亲自去看看那里到底是怎么回事。</p><p>我在那儿待了半个月,以下是我的发现:</p><p><strong>1) 56,483 个人</strong></p><p>在今天地球上的 72 亿人里,有 56,483 个人在格陵兰过日子。这比曼哈顿东村 (East Village) 的人口还少,让格陵兰成为地球上人口密度最低的国家(每 15 平方英里才有一个人)。蒙古是地球上密度第三低的国家,而它的密度是格陵兰的 65 倍。就算你只算格陵兰沿海那圈没被冰盖住的地区(那些海岸带加起来大概相当于瑞典的面积),格陵兰仍然是全世界人口密度最低的国家,遥遥领先。</p><p>那么这 56,483 个人是谁,他们又是怎么跑到格陵兰去的?</p><p>绝大多数是卡拉利特人 (Kalaallit),一支因纽特人 (Inuit),<a href="#footnote-3-2432">3</a> 他们的祖先是图勒人 (Thule),几千年前从亚洲跨越白令海峡迁徙而来。但通往格陵兰的路很长,要一路穿过阿拉斯加和加拿大北部,图勒人最终到达格陵兰的时间差不多正是西班牙人抵达新世界的时候——所以他们相对于格陵兰的&quot;原住民&quot;身份,并不比欧洲后裔相对于美洲的原住民身份更强。</p><p>格陵兰超过 4/5 的人口住在西海岸的南半段,如果他们想从一个地方到另一个地方,靠的是雪地摩托、狗拉雪橇,预算大的话就走空运或海运。格陵兰城镇之间没有公路相连。至于那些城镇,看起来美味极了,房子都刷得五颜六色:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_53521.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt="IMG5352"></a></p><p>官方语言是格陵兰语,但大多数人也会说丹麦语,有些人还会说英语。他们讲丹麦语是因为丹麦在 18 世纪初就对这片土地确立了主权。<a href="#footnote-4-2432">4</a> 格陵兰在 1979 年获得了内部自治权,如今基本上像一个独立国家一样运转(有人告诉我,年轻一代对丹麦尤其感到厌烦,而热衷于自己的格陵兰文化)。</p><p>说到格陵兰的经济,渔业就是一切——鱼类和鱼类产品,尤其是虾,占出口总额的 89%。</p><p>人口内部还有一些阴暗的东西在发生。据<a href="http://www.who.int/healthinfo/mortality_data/en/" target="_blank" rel="noreferrer">世界卫生组织</a>统计,全球自杀率是每 10 万人中有 16 人。各国的数字从每 10 万人不到 1 人到高达 31 人不等(立陶宛是自杀率最高的国家)。问题是,格陵兰不在这份名单上,因为它不是独立国家。如果它是的话,它将<em>远远</em>成为自杀率最高的国家,达到每 10 万人<em>107</em>起自杀。政府报告说,每 5 个格陵兰人中就有 1 人在人生某个阶段试图自杀,而我在那里跟一些人聊过,他们说几乎每个格陵兰人都认识一个自杀的人。合乎逻辑的结论应该是:自杀高峰出现在几乎全天黑暗的冬季——但事实恰恰相反,更明亮的月份带来失眠潮,自杀在那时更频繁。</p><p>这个国家还有严重的酗酒问题,这可能与自杀率相关,也可能两者都是别的什么东西的症状——有一种理论把矛头指向一个直到不久前还非常传统的文化中所经历的急速现代化。</p><p>在有限的停留时间里,我发现这里的人总体上非常善良,但也相当害羞,对外国人有几分戒备,这让今年夏天在这里比在别的地方更难跟当地人建立起表面之下的了解。</p><p><strong>2) 一块重达 2,565,000,000,000,000 吨的冰块</strong></p><p>冰河期发生的原因,是地球轨道的一次微妙偏移让全球温度稍稍变冷了一点。变化不必很大,但随着时间推移,就会演变成一个冰河期,<a href="https://en.wikipedia.org/wiki/Pleistocene#mediaviewer/File:Blakey_Pleistmoll.jpg" target="_blank" rel="noreferrer">巨大的冰盖</a> 在两极堆积起来,然后向赤道方向扩张,一路造成浩劫——长岛和科德角不过是上一次冰期北美巨型冰盖横扫时撕下来的碎片,而五大湖不过是被冰盖从地表刨出来的凹坑,在冰盖退缩时被融水灌满了而已。</p><p>这些巨大的冰盖之所以形成并扩张,并不是因为下了更多的<em>雪</em>,而是因为温度的微小变化意味着每年<em>融化</em>的雪变少了,于是缓慢地开始堆积。白色的雪又反射了更多阳光,让地面吸收得更少,进一步加剧了这个效应。一层一层的雪不断堆积,直到在自身重量下变成坚硬如岩石的冰——冰盖就是这么形成的。</p><p>冰期长达数百万年,由交替出现的两种时期组成:寒冷的冰川期 (glacials)(通常持续 4 万到 10 万年)和短暂温和的间冰期 (interglacials)(持续约 1 万年)。你可以把间冰期想成冰期在进入下一个冰川期之前的一次「暂停」。当你听说「上一次冰期在 1 万年前」时,你实际上听到的是我们<em>目前所处的这个冰期</em>中的上一次<em>冰川期</em>。我们之所以没意识到自己正处在冰期的正中间,是因为我们——以及所有有文字记载的人类历史——都发生在其中一个小小的间冰期暂停时段里。这就是为什么现在北极和南极还有冰盖、地球上很多其他地方(甚至像新西兰这样的温带地区)还有冰川——因为我们正处于一个冰期之中。而在没有冰期的时候,地球上任何地方都没有冰盖(地球历史的 85% 都是这种状态)。</p><p>到目前为止,这个冰期里已经出现过 17 对冰川期/间冰期,科学家预测在地球彻底走出这个冰期之前,还会再来多达 50 对,每对最长可达 10 万年。而我们现在所处的这个间冰期已经异常地长了——看起来下一个冰川期该来了。</p><p>说到全球变暖:从长远来看,有两个因素远远超出人类的影响——即将到来的下一个冰川期,不管我们喜不喜欢,它都会把我们冻个透心凉;以及这个大冰期的最终结束,不管我们做什么,它都会融化所有的极地和南极冰盖并抬升海平面——但地质时钟走得太慢了,这些事情都是在几千年、几百万年的尺度上发生的,而让科学家们心惊胆战的全球变暖效应,却可能在未来几百年内、在这些更大的力量还没怎么动弹之前,就给人类带来灾难。</p><p>回到格陵兰。所以由于「下雪比融雪多」的那种堆积现象,格陵兰现在头上顶着一块我喜欢称之为「2,565,000,000,000,000 吨的冰块」的东西。关于这块大冰块的一些事实:</p><ul><li>不,那不是一个立方体,那是一大片冰盖</li><li>它重达 2.565 千万亿吨,相当于 75 亿座帝国大厦的重量</li><li>它的平均高度/厚度超过 2 公里,最厚处超过 3 公里。想象 10 座摩天大楼叠在一起——它们仍然会被埋在冰下。就是这么厚。</li><li>如果它全部融化,全球海平面将上升 23 英尺,几乎所有沿海城市都会被淹没</li><li>现在把我刚才说的一切都<em>乘以十</em>,你就得到了南极冰盖</li><li>这两片冰盖加起来含有地球上超过 99% 的淡水冰,以及全世界超过 2/3 的淡水<a href="#footnote-5-2432">5</a></li></ul><p>有一天我去了干燥的沿海陆地终结、冰盖开始的边缘。看起来是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_2738.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Ice Sheet - Close"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5685.jpg" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Ice Sheet (far)"></a></p><p>由于格陵兰冰盖的重量,岛屿内部被压得下沉了一点,使格陵兰变得有点像一个碗,四周被群山环绕。最终,随着越来越多的冰堆积起来,一些冰不可避免地会&quot;溢出&quot;碗的边缘。这就是冰川。位于格陵兰东北部的象足冰川 (Elephant Foot Glacier) 就是一个完美的溢出例子:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/4874_1dd7.jpeg" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Elephant Foot Glacier"></a></p><p><em><a href="http://emilie34.soup.io/post/228424752/Elephant-Foot-Glacier-in-Greenland" target="_blank" rel="noreferrer">Emilie34</a></em></p><p>而当冰川最终延伸到海洋时,一部分会崩裂到水中——这就是冰山的来源。格陵兰的冰川每年会崩裂出 12000 到 15000 座冰山。</p><p>北半球最活跃的冰川位于西海岸中段的伊卢利萨特 (Ilulissat) 镇附近,一条巨大的冰川在一条狭窄峡湾的入海口倾泻入海,将峡湾填满了巨大的冰山。这是那条峡湾,而透过雾看到的那座&quot;山&quot;其实不是山——那是一座巨大的冰山:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5633.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Ice Fjord"></a></p><p>当你看着这些冰山时,想想一杯<a href="http://images.sodahead.com/polls/002576145/5848413814_ice_water_xlarge.jpeg" target="_blank" rel="noreferrer">加了冰块的饮料</a>。你知道漂浮的冰块大部分都在水面之下,只有一小角露出水面吗?这些冰山也是这样——你在水面上看到的大约只是整座冰山的 1/8——</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/iceberg.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt="iceberg"></a></p><p><em><a href="http://ralphclevenger.com/portfolios/earth/" target="_blank" rel="noreferrer">Ralph Clevenger</a></em></p><p>这个事实一直让我震撼不已。你看看这张照片,拍的是峡湾汇入大洋的地方:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5651.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Iceberg"></a></p><p>有人告诉我,后面那座巨大的冰山有一栋 40 层楼那么高——是<em>水面以上</em>。也就是说,水下部分向下延伸约 3200 英尺——<em>比<a href="https://upload.wikimedia.org/wikipedia/en/9/93/Burj_Khalifa.jpg" target="_blank" rel="noreferrer">哈利法塔 (Burj Khalifa)</a> 还要深。</em></p><p>而这还不算什么。今年 5 月,一座比曼哈顿还大的冰山从冰川上断裂下来,顺着同一条峡湾漂了下去。<a href="#footnote-6-2432">6</a></p><p>1909 年,一座冰山从这些照片里的同一条冰川上断裂,花了三年时间穿过冰峡湾、漂进北大西洋,然后在 1912 年撞沉了泰坦尼克号:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Titanic_iceberg.jpg" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Titaniciceberg"></a></p><p>这张照片拍的就是撞沉泰坦尼克的那座冰山</p><p><strong>3) 21000 只狼</strong></p><p>它们到处都是。而且它们其实不是狼,是一种古老的类狼犬种,是第一批因纽特定居者带到格陵兰的狗的后代。但它们长得像狼,叫起来像狼,当我走在路上,以为一切正常,然后一转头看到左边有 40 只这种家伙就在那儿,拴着链子,每一只都在我经过时目不转睛地盯着我——它们把我吓得屁滚尿流,就跟真的狼一样。<a href="#footnote-7-2432">7</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5606.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Dogs"></a></p><p>这些狗当然是用来拉雪橇的。这里没有长途公路,狗拉雪橇既是关键的交通方式,也是一项竞技运动。因为是夏天,我没机会试,但我问了很多问题——显然,你并不是像我想象的那样坐在雪橇上悠哉游哉,让狗带着你兜风。你是站在滑雪板上的,全神贯注,全程都得费力操作。而且还挺危险的——如果你在冰上偏远的地方从雪橇上摔下来,狂奔的狗群里噪音太大,它们可能听不到你喊停,然后就直接跑掉,把你留在原地等死。也有过狗攻击并咬死骑手的记录。有个有趣的冷知识是,狗有时候在跑的过程中需要拉屎,但整个队伍不会为这个停下,所以它们只能一边拉一边被以全速拖着走。</p><p>格陵兰犬天生就为艰苦的雪橇任务打造,为了保持这一点,格陵兰禁止任何其他品种的狗被带到北极圈以北,以免它们跟格陵兰犬杂交,毁掉这一血统的纯正性。反过来,任何格陵兰犬也不许被带到北极圈以南——一旦带下去,就再也不能回来了。</p><p>我还有个明显的感觉:狗在这里更多是被当作装备而不是宠物。我在各处看到它们时,它们就那么呆坐着,拴在柱子上,周围一个人都没有。我听说全国只有两个兽医,这意味着面对生病或受伤的狗,除了一枪打死之外,做任何别的都是荒唐的概念。哦,还有,这里关于拴狗的法律相当严格——在我去过的一个镇子上,每周三中午 12 点到下午 2 点之间,会有个警察开车四处转悠,看见没拴的狗就开枪打死。</p><p><strong>4) 一个单词</strong> <strong>nalunaarasuartaateraliornialersaaraluaranimgooruna</strong></p><p>意思是灯塔。</p><p>你知道西班牙语和意大利语是紧密相关的语言,两者之间有很多相似的词和发音吗?你知道西班牙语和英语也有相似之处,但关系更远一些吗?你知道西班牙语和挪威语之间的距离又更远吗?你知道西班牙语和普通话<em>真的</em>离得非常远,你几乎找不到任何相似之处吗?语言学就像进化——所有语言在过去<em>某个地方</em>都是相关的,但两种语言的分支点越早,一种语言在另一种语言使用者听来就越奇怪。</p><p>嗯,格陵兰语属于爱斯基摩-阿留申语系,这意味着它在语言学树上离英语这样的印欧语系<em>真的、真的</em>非常遥远。<a href="#footnote-8-2432">8</a></p><p>看看这段文字。是不是<em>很怪</em>?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5433.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Greenlandic"></a></p><p>我试着搞懂一些发音,搞了一会儿就放弃了,把注意力全部转向数每个词里有多少个字母,试图找出最长的那个词。灯塔。</p><p><strong>5) 阴森感</strong></p><p>订格陵兰机票的时候我就有种预感,可能会去一个阴森的地方,但我没想到自己会在这本书里度过两周:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/1325218.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Scary Book"></a></p><p>那边正发生着的是这类破事:</p><ul><li><p>先从回荡在整片土地上的狼嚎开始吧。</p></li><li><p>然后是我跟一个在那儿住了十年的丹麦人的对话,他说格陵兰有时会发生一些奇怪或令人不安的事,外面的世界根本听不到。他没有细说。</p></li><li><p>在路边,你会看到诸如<a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5666.jpg" target="_blank" rel="noreferrer">这架飞机残骸</a>之类的东西,残骸里躺着<a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5674.jpg" target="_blank" rel="noreferrer">这个可乐罐</a>。</p></li><li><p>一个当地人带我沿着一条徒步小径看了大地上的各种裂缝,你可以看到底下埋着的人骨。</p></li><li><p>很多格陵兰人相信鬼魂,许多人因为这种恐惧而开着灯睡觉。</p></li><li><p>格陵兰岛上显然有一种叫 qivitoqs 的东西,好几个人都特意跟我讲过。传说他们是半死半活的人,力气像野兽,夜里在大地上游荡。一个家伙告诉我这是真事——他们其实是活生生的人,要么是小时候受过虐待逃了出来,要么是被村子放逐的,一辈子独自在荒野里自谋生路。活下来的人最终变得非常强壮,想要复仇,而且常常神志不清,据说他们会在离开多年后重新出现在某个村庄,然后杀人。他说,有时人们会在自家偏僻小屋外的雪地上看到脚印,而他们清楚家里没人往那儿走过。麻烦给我一张回伊拉克的机票,谢谢。</p></li><li><p>这让我跑到网上去查<a href="http://www.unodc.org/documents/gsh/data/GSH2013_Homicide_count_and_rate.xlsx" target="_blank" rel="noreferrer">各国凶杀率</a>统计,结果发现凶杀率最高的 25 个国家里有 24 个都在拉美和非洲。剩下那一个是谁?格陵兰。</p></li><li><p>法律规定囚犯必须在晚上 9:30 到早上 6:00 之间待在牢房里,但其他时间他们<a href="http://www.huffingtonpost.com/2012/01/04/greenland-prison-system_n_1181697.html" target="_blank" rel="noreferrer">想出去就出去</a>。</p></li><li><p>更帮倒忙的是夜里突然传来的噼啪声和轰鸣声——冰山断裂发出的,还有风穿过巨大的地面裂缝时,常常发出像人一样的声音。</p></li></ul><p><strong>6) 圣诞老人</strong></p><p>反过来讲,圣诞老人住在格陵兰。</p><p>你知道小孩子给圣诞老人写信,把信封地址写成&quot;北极&quot;,这事儿听起来傻乎乎的,然后就没下文了对吧?好吧,我现在了解到,在世界上很多地方,那些信真的会被寄到某个地方——寄到格陵兰岛中部一个叫伊卢利萨特 (Ilulissat) 的 4500 人小镇上的一个大红邮箱里。我一开始也不信。</p><p>但等我到了伊卢利萨特,直奔那个据说存在的邮箱而去时,我惊呆了——不仅邮箱真的在那儿,透过它的玻璃前面,还能看到里面有成千上万封来自世界各地写给圣诞老人的信。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5604.jpg" target="_blank" rel="noreferrer"><img src="'+G+'" alt="Santa Mailbox Ilulissat"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5597.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt="Santa Mail and Pacifiers"></a></p><p>更疯狂的是,那个跟我讲雪地幽灵脚印的家伙还告诉我,镇上有一群人自愿给每个孩子回信,而他就是其中之一——<em>他就是圣诞老人。</em></p><p>我就这件事问了他 2500 个问题,了解到以下内容:</p><ul><li>圣诞老人用谷歌翻译回信给孩子们,不管他们说什么语言</li><li>所有信件都是手写的</li><li>所有信件都会得到回复</li><li>那个箱子里有好几百个奶嘴,我看到时惊呆了,他解释说,家长们经常用「把奶嘴寄给圣诞老人」的办法来哄孩子戒掉奶嘴</li><li>丹麦的孩子不会被告知圣诞老人住在北极。他们被告知圣诞老人住在格陵兰。丹麦父母是基督教世界里唯一不对孩子撒谎的父母</li></ul><p><strong>我作为 Berthelina 的同居伴侣度过的三天——她是一个格陵兰小镇上 72 岁的、全镇人的祖母</strong></p><p>一系列奇怪的文章,不如就以一个奇怪的方式来结尾。</p><p>我从没想过我会花三天时间当 Berthelina Inukitsoq 的室友,她也从没想过要花三天时间当我的室友。但当我开始打听能不能去一个小村子住几天时,一堆奇怪的多米诺骨牌倒下了,最后我就在一个叫 Oqaatsut 的 46 人小村庄里,住进了她家。</p><p>跟格陵兰所有地方一样,去 Oqaatsut 并不容易。对我来说,这需要两趟飞机加一段漫长的船程。我终于到了这里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5407.jpg" target="_blank" rel="noreferrer"><img src="'+I+'" alt="Greenland Village"></a></p><p>北极圈里一个与世隔绝的 46 人小镇,这本身就是个很猛的概念。这一点我一到新家就立刻明白了——我见到了 Berthelina,得知那天是她 72 岁生日。这意味着她整天都在接待来访的家人和朋友,所以我到了之后就在沙发上坐了三个小时,<em>就见到了全镇 90% 的人。<em>不仅如此,我数了一下我遇到的 Berthelina 的子女、儿媳女婿或孙辈,这一数就超过了 Oqaatsut 人口的</em>一半</em>。我住的地方是全镇祖母的家。</p><p>居民们轮番从客厅经过,我尝试从任何会说一点英语的人那里了解这个小镇。我见到了 Berthelina 的儿子,一位狗拉雪橇比赛的选手,架子上所有的<a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5393.jpg" target="_blank" rel="noreferrer">奖杯</a>都是他赢来的。他同时也是小镇的店主。以及镇长。后来,当我问起如果有纠纷会怎样时,我发现他还是警长。真的是。</p><p>他妻子是村里餐馆的厨师,他兄弟——也是 Berthelina 的儿子——是村里两个渔夫之一,为整个村子提供了大部分食物。我了解到今年对所有人来说都是个好年头,因为几周前他们捕到了一头鲸鱼:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5523.jpg" target="_blank" rel="noreferrer"><img src="'+M+'" alt="Whale 1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5522.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt="Whale 2"></a></p><p>他们留了一小部分鲸肉给村子自己吃,剩下的卖给了 4500 人的 Ilulissat 镇。</p><p>派对上还来了镇上的老师,以及镇上仅有的两名学生——两个十几岁的女孩,她们真的必须确保自己喜欢彼此。</p><p>村里有一个小型发电站,为各家各户供电,但没有下水系统。粪便每隔几天由村里的一个人收集起来,倒到村外一个指定的垃圾场。自来水只在一间公共浴室里有,浴室在特定时段开放;而饮用水则是靠融化漂在水里的众多冰山中的一小块获得的。<a href="#footnote-9-2432">9</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5529.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt="Melting Ice"></a></p><p>派对的最低谷是我试图讨好一个 3 岁小孩,给她看我之前拍的一段羊驼吃东西的视频,结果视频开始才两秒,她就判定我无关紧要,转身离开了,可就在这两秒里,两个大人凑过来想看视频,于是我和两个大人尴尬地坐在一起,看着这段视频播放了整整 14 秒:</p><p>总之,派对终于散场了,剩下 Berthelina 和我不得不面对我们是室友这个事实。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/IMG_5537.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Roommates"></a></p><p>室友</p><p>我们没法互相交流,所以我们采用了 B 方案,也就是 Berthelina 对一切完全无所谓,而我像她的狗一样在她身边转悠。我们找到了一种不错的默契,过了一会儿,她上楼睡觉了。</p><p>屋子突然显得有点瘆人,因为没有别人在(记住这时候我在旅程中已经处于惊魂未定的状态),于是我决定出去走走,结果<em>刚</em>出门一秒钟,就发生了这个:</p><p>不。我不知道那是什么意思,但不。所以我立刻掉头回屋,走进卧室,看到架子上散放着一堆<em>一点都不酷的画</em>。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/09/Scary-Compilation.jpg" target="_blank" rel="noreferrer"><img src="'+S+'" alt="Scary Compilation"></a></p><p>我到现在都不知道是谁他妈画的那些画,但那时候我的心理状态已经太脆弱了,承受不了在寂静漆黑的卧室里撞见它们。那一整晚我都在两种恐惧之间来回切换——一会儿担心墙上会移过一个鬼影,一会儿又担心门会砰地被撞开,一个 qivitoq 冲进来把我杀了。真不是什么好时光。</p><p>接下来的几天,除了参观了一次学校,还有一个下午跟渔夫出海看那些懊悔的鱼在塑料箱里扑腾之外,我大部分时间都在跟着 Berthelina,看她过日常生活——听收音机,和朋友玩宾果,烤了两次松饼,切了条鱼,融化冰块。当 Berthelina 其实还挺不错的。</p><p>不到一周之后,我时隔近三个月第一次回到纽约,头两天对几乎所有事情都感到 <em>震惊</em>,然后立刻又变得麻木,把一切重新视作理所当然。而奥卡楚特突然显得远得离谱。</p><p>一个三分钟的短片,总结我在格陵兰的时光:</p><p><strong>其他几站:</strong><br><a href="https://waitbutwhy.com/2014/07/russia-what-you-didnt-know.html" target="_blank" rel="noreferrer">俄罗斯</a><br><a href="https://waitbutwhy.com/2014/07/japan-and-how-i-failed-to-figure-it-out.html" target="_blank" rel="noreferrer">日本</a><br><a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">尼日利亚</a><br><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">伊拉克</a></p><p><a href="https://waitbutwhy.com/2014/09/genie-question.html" target="_blank" rel="noreferrer">我在这五个国家都问过大家的那个神灯问题</a></p><h2 id="还有另一次去的朝鲜" tabindex="-1">还有另一次去的<a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">朝鲜</a> <a class="header-anchor" href="#还有另一次去的朝鲜" aria-label="Permalink to &quot;还有另一次去的[朝鲜](https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>给新读者:这些编号小圆圈是文中额外的事实、想法或解释——通常不是用来放参考资料的,所以如果你不赶时间,点开看看。总之,注 1 是:格陵兰 (Greenland) 不是一个独立国家——它是丹麦王国 (Kingdom of Denmark) 的一部分——但最近它被认定为「自治国」,意思是它在大多数方面像独立国家一样运作,只是并非事事如此。本文中,我会把它称为一个国家。<a href="#note-1-2432">↩</a></p></li><li><p>红发埃里克 (Erik the Red) 的儿子是莱夫·埃里克森 (Leif Erikson),他当年正从挪威前往格陵兰,打算去那里传播基督教,结果被风吹偏了航线,成了第一个登上北美大陆的欧洲人(他把这片土地命名为文兰 (Vinland))——比哥伦布的航行早了 500 年。<a href="#note-2-2432">↩</a></p></li><li><p>所以你是不是觉得「爱斯基摩人 (Eskimo)」这个词老土又带有歧视色彩,「因纽特人 (Inuit)」才是政治正确的用法?其实事情没那么简单。格陵兰、加拿大北部以及阿拉斯加部分地区的原住民<strong>是</strong>因纽特人,叫他们因纽特人没问题。但阿拉斯加原住民中很大一部分是尤皮克人 (Yupik),他们<strong>不是</strong>因纽特人,把他们叫成因纽特人是很冒犯的。而因为阿拉斯加既有因纽特人也有非因纽特人,所以其实更推荐把他们统称为爱斯基摩人,这个词可以泛指所有阿拉斯加原住民。另一方面,在加拿大北部和格陵兰,绝大多数原住民都是因纽特人,爱斯基摩这个词就被视为冒犯了。这个词带有负面含义,部分原因是长期以来人们以为它是帝国主义者发明的,意思是「吃生肉的人」——谁想被这么叫啊。事实上,现在的观点认为它源自一个古老的爱斯基摩-阿留申语 (Eskimo-Aleut) 词汇,意思是「织雪鞋网的人」,显然这就没那么冒犯了。真是让人迷糊。只要记住——把阿拉斯加原住民叫爱斯基摩人,其他地方的都叫因纽特人(或者如果你想当个不那么笨的人,就用他们真正的具体族群名字叫他们——尤皮克、伊努皮亚特 (Inupiat) 等等——但你我心里都清楚,你根本记不住)。<a href="#note-3-2432">↩</a></p></li><li><p>1946 年美国曾出价 1 亿美元向丹麦购买格陵兰,被拒绝了。<a href="#note-4-2432">↩</a></p></li><li><p>我以前写过<a href="https://waitbutwhy.com/2013/09/putting-all-worlds-water-into-big-cube.html" target="_blank" rel="noreferrer">一篇短文</a>聊这个话题。<a href="#note-5-2432">↩</a></p></li><li><p>2012 年,两个人<a href="https://www.youtube.com/watch?v=hC3VTgIPoGU" target="_blank" rel="noreferrer">用相机拍到</a>一块曼哈顿大小的冰从格陵兰冰川上崩落。有记录以来最大的冰山<a href="http://www.livescience.com/31011-giant-chunk-12-year-iceberg-caught-camera.html" target="_blank" rel="noreferrer">有牙买加那么大</a>,2000 年从南极的罗斯冰架 (Ross Ice Shelf) 上崩落——花了 12 年才融化。<a href="#note-6-2432">↩</a></p></li><li><p>我查资料读关于狼和狗的内容时,了解到吠叫只占狼所有发声的 2.3%,而且被视为一种罕见现象。狼里面主要是幼崽会吠。但家犬不管几岁都一直在叫。这被解释为培育温顺性的副产品——通过选育温顺性,人类的驯化无意中造就了一辈子都表现得像幼崽的狗:它们服从的姿态、呜咽、耷拉的耳朵,还有吠叫,都是幼态特征。我在格陵兰几乎没听到狗叫,因为它们不是我熟悉的那种狗——它们是狼。<a href="#note-7-2432">↩</a></p></li><li><p>冷知识:「igloo (冰屋)」和「kayak (皮划艇)」这两个词都是英语从格陵兰语借来的。<a href="#note-8-2432">↩</a></p></li><li><p>喝到某一刻,我意识到这水真挺酷的。自从人类还都是狩猎采集者的时代起,它就再没变回液态了。它 10000 多年前作为雪落在冰盖顶上,从那时起就一直是冰的形态。<strong>终于</strong>又变回水了,结果立刻就被人喝掉,真是够惨的。<a href="#note-9-2432">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">推文</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/09/but-what-about-greenland.html&amp;description=But%20What%20About%20Greenland?" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p>',126)])])}const U=e(A,[["render",E]]);export{R as __pageData,U as default};
